758→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
759→  LET $query = string::lowercase(string::trim($q));
760→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
