  const stmts = [];
  let current = "";
  let depth = 0;
  for (let i = 0; i < sql.length; i++) {
    const ch = sql[i];
    if (ch === "{") depth++;
    else if (ch === "}") depth--;

    if (ch === ";" && depth === 0) {
      const trimmed = current.trim();
      if (trimmed.length > 0) stmts.push(trimmed);
      current = "";
    } else {
      current += ch;
    }
  }
  const trimmed = current.trim();
  if (trimmed.length > 0) stmts.push(trimmed);
  return stmts;
}

