import { readFileSync } from "fs";
import { join } from "path";
import { Surreal } from "surrealdb";

function splitSqlStatements(sql: string): string[] {
  const stmts: string[] = [];
  let current = "";
  let depth = 0;
  for (let i = 0; i < sql.length; i++) {
    const ch = sql[i];
    if (ch === "{") depth++;
    else if (ch === "}") depth--;
    if (ch === ";" && depth === 0) {
      const trimmed = current.trim();
      if (trimmed.length > 0) stmts.push(trimmed);
      current = "";
    } else {
      current += ch;
    }
  }
  const trimmed = current.trim();
  if (trimmed.length > 0) stmts.push(trimmed);
  return stmts;
}

async function main() {
  const surreal = new Surreal();
  await surreal.connect(process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc");
  await surreal.signin({ username: "root", password: "root" });

  const ns = `debug_${Date.now()}`;
  const db = `debug_${Math.floor(Math.random() * 100000)}`;
  await surreal.query(`DEFINE NAMESPACE ${ns};`);
  await surreal.use({ namespace: ns });
  await surreal.query(`DEFINE DATABASE ${db};`);
  await surreal.use({ namespace: ns, database: db });

