  const withoutComments = schemaSql.split("\n").filter((line) => !line.trimStart().startsWith("--")).join("\n");
  const statements = splitSqlStatements(withoutComments);

  const analyzerStmts = statements.filter((s) => s.startsWith("DEFINE ANALYZER"));
  const schemaStmts = statements.filter((s) => !s.startsWith("DEFINE ANALYZER") && !s.startsWith("CREATE"));
  const seedStmts = statements.filter((s) => s.startsWith("CREATE"));

  console.log(`Phase 1: ${analyzerStmts.length} analyzer stmts`);
  for (const stmt of analyzerStmts) {
    try { await surreal.query(stmt + ";"); console.log("  OK"); } 
    catch (e: any) { console.log(`  FAIL: ${e.message?.substring(0, 100)}`); }
  }

  console.log(`\nPhase 2: ${schemaStmts.length} schema stmts (sending as batch)`);
  try {
    const results = await surreal.query(schemaStmts.map((s) => s + ";").join("\n"));
    console.log(`  Got ${results.length} results`);
    // Check for errors in results
    let errors = 0;
    for (let i = 0; i < results.length; i++) {
      const r = results[i];
