        errors++;
        if (errors <= 5) console.log(`  ERR at [${i}]: ${JSON.stringify(r).substring(0, 150)}`);
      }
    }
    console.log(`  Errors: ${errors}`);
  } catch (e: any) {
    console.log(`  BATCH FAIL: ${e.message?.substring(0, 200)}`);
  }

  console.log(`\nPhase 3: ${seedStmts.length} seed stmts (sending as batch)`);
  try {
    const results = await surreal.query(seedStmts.map((s) => s + ";").join("\n"));
    console.log(`  Got ${results.length} results`);
    let errors = 0;
    let empty = 0;
    for (let i = 0; i < results.length; i++) {
      const r = results[i];
      if (r && typeof r === 'object' && 'status' in r && r.status === 'ERR') {
        errors++;
        if (errors <= 5) console.log(`  ERR at [${i}]: ${JSON.stringify(r).substring(0, 200)}`);
      }
      if (Array.isArray(r) && r.length === 0) empty++;
    }
    console.log(`  Errors: ${errors}, Empty: ${empty}`);
  } catch (e: any) {
    console.log(`  BATCH FAIL: ${e.message?.substring(0, 200)}`);
  }

  // Check if authority_scope has data
