  console.log(`\nauthority_scope count: ${JSON.stringify(rows)}`);

  // Cleanup
  await surreal.query(`REMOVE DATABASE ${db};`);
  await surreal.query(`REMOVE NAMESPACE ${ns};`);
  surreal.close();
}
