  1→/**
  2→ * BM25 fulltext search query builders and execution.
  3→ *
  4→ * Pattern:
  5→ *   1. Per-table SELECT ... WHERE field @N@ $query AND workspace = $ws
  6→ *   2. search::score(N) returns BM25 relevance score
  7→ *   3. RRF (./rrf.ts) merges per-table ranked lists by rank position
  8→ *
  9→ * SurrealDB 3.0.4+: @N@ works with SDK bound parameters ($query).
 10→ * search::score() returns real BM25 scores with BM25(1.2, 0.75).
 11→ */
 12→
 13→import type { Surreal } from "surrealdb";
 14→import type { RecordId } from "surrealdb";
 15→import type { RankedEntity, SearchEntityKind } from "./queries";
 16→import { applyRrf, type RrfItem } from "./rrf";
 17→
 18→// ---------------------------------------------------------------------------
 19→// Pure query builders
 20→// ---------------------------------------------------------------------------
 21→
 22→const ALL_SEARCH_KINDS: SearchEntityKind[] = [
 23→  "project", "feature", "task", "decision", "question", "suggestion",
 24→];
 25→
 26→/** Table-to-text-field mapping for BM25 search */
 27→const TABLE_TEXT_FIELD: Record<SearchEntityKind, { textField: string; kindLabel: string }> = {
 28→  task:       { textField: "title",   kindLabel: "task" },
 29→  decision:   { textField: "summary", kindLabel: "decision" },
 30→  question:   { textField: "text",    kindLabel: "question" },
 31→  feature:    { textField: "name",    kindLabel: "feature" },
 32→  project:    { textField: "name",    kindLabel: "project" },
 33→  suggestion: { textField: "text",    kindLabel: "suggestion" },
 34→};
 35→
 36→/**
 37→ * Build BM25 fulltext search SQL across entity tables.
 38→ *
 39→ * Returns a multi-statement SQL string with one SELECT per table.
 40→ * Each SELECT returns { id, kind, text, status, score } rows.
 41→ *
 42→ * Requires bound parameters: $workspace, $limit, $query
 43→ */
 44→export function buildBm25SearchSQL(
 45→  kinds?: SearchEntityKind[],
 46→): string {
 47→  const selectedKinds = kinds && kinds.length > 0 ? kinds : ALL_SEARCH_KINDS;
 48→
 49→  const statements = selectedKinds.map((kind) => {
 50→    const { textField, kindLabel } = TABLE_TEXT_FIELD[kind];
 51→    const workspaceFilter = kind === "project"
 52→      ? `id IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace)`
 53→      : `workspace = $workspace`;
 54→
 55→    return `SELECT id, "${kindLabel}" AS kind, ${textField} AS text, status, search::score(1) AS score
 56→FROM ${kind} WHERE ${textField} @1@ $query AND ${workspaceFilter} ORDER BY score DESC LIMIT $limit;`;
 57→  });
 58→
 59→  return statements.join("\n\n");
 60→}
 61→
 62→// ---------------------------------------------------------------------------
 63→// BM25 search result row type (from SurrealDB)
 64→// ---------------------------------------------------------------------------
 65→
 66→type Bm25SearchRow = {
 67→  id: RecordId<string, string>;
 68→  kind: SearchEntityKind;
 69→  text: string;
 70→  status?: string;
 71→  score: number;
 72→};
 73→
 74→// ---------------------------------------------------------------------------
 75→// Effect boundary: execute BM25 search against SurrealDB
 76→// ---------------------------------------------------------------------------
 77→
 78→export async function searchEntitiesByBm25(input: {
 79→  surreal: Surreal;
 80→  workspaceRecord: RecordId<"workspace", string>;
 81→  query: string;
 82→  kinds?: SearchEntityKind[];
 83→  limit: number;
 84→}): Promise<RankedEntity[]> {
 85→  const trimmed = input.query.trim();
 86→  if (trimmed.length === 0) {
 87→    return [];
 88→  }
 89→
 90→  const sql = buildBm25SearchSQL(input.kinds);
 91→  const bindings = {
 92→    workspace: input.workspaceRecord,
 93→    limit: input.limit,
 94→    query: trimmed,
 95→  };
 96→
 97→  const results = await input.surreal.query(sql, bindings);
 98→
 99→  // Group results into per-table ranked lists for RRF fusion
100→  const allArrays = (results as unknown as Bm25SearchRow[][]).filter(Array.isArray);
101→  const rankedLists = allArrays.map((rows) =>
102→    rows.map((row) => ({
103→      _rrfKey: `${row.kind}:${row.id.id as string}`,
104→      id: row.id,
105→      kind: row.kind,
106→      text: row.text,
107→      status: row.status,
108→      score: row.score,
109→    } as const satisfies RrfItem<Bm25SearchRow>)),
110→  );
111→
112→  const fused = applyRrf(rankedLists, input.limit);
113→
114→  return fused.map((row) => ({
115→    id: row.id.id as string,
116→    kind: row.kind,
117→    name: row.text,
118→    score: row.rrfScore,
119→    ...(row.status ? { status: row.status } : {}),
120→  }));
121→}
