async function findSimilarByBm25(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  searchText: string,
  spec: Bm25SearchSpec,
): Promise<Bm25Candidate[]> {
  const sql = `SELECT id, ${spec.textField} AS text, search::score(1) AS score
FROM ${spec.table}
WHERE ${spec.textField} @1@ $query
AND workspace = $ws
${spec.extraFilter}
ORDER BY score DESC
LIMIT 10;`;

  // BM25 @N@ does AND matching — >4-5 terms silently return empty results.
  const terms = extractSearchTerms(searchText);
  if (terms.length === 0) return [];

  const [rows] = await surreal.query<[Array<{ id: RecordId; text: string; score: number }>]>(
    sql,
    { ws: workspaceRecord, query: terms },
  );

  return (rows ?? []).map((row) => ({
    id: row.id.id as string,
    text: row.text,
    score: row.score,
  }));

